CURRENT_SESSION=$(ls -t ~/.claude/projects/-home-jsbattig-Dev-claude-pace-maker/*.jsonl 2>/dev/null | head -1); tail -10 "$CURRENT_SESSION" | python3 -c "
import sys, json
for i, line in enumerate(sys.stdin):
    try:
        e = json.loads(line)
        keys = list(e.keys())
        print(f'Entry {i}: keys={keys}')
        if 'message' in e:
            msg = e['message']
            print(f'  role={msg.get(\"role\")}, content_types=', end='')
            c = msg.get('content', [])
            if isinstance(c, list):
                print([b.get('type','?') if isinstance(b, dict) else type(b).__name__ for b in c])
            else:
                print(f'str({len(c)} chars)')
        elif 'type' in e:
            print(f'  type={e[\"type\"]}')
    except Exception as ex:
        print(f'Entry {i}: parse error: {ex}')
"
